mapper.select:
SELECT LEARNING_REPORT_NUMBER, MATCHING_NUMBER, SUBJECT_NUMBER, SUBJECT_TITLE, SUBJECT_SUMMARY, SUBJECT_CONTENT, REPORT_WEEK, REPORT_SESSION, TO_CHAR(REPORT_DATE, 'YYYY-MM-DD') AS REPORT_DATE FROM UB_LEARNING_REPORT WHERE MATCHING_NUMBER = #{matchingNumber}
AND REPORT_DATE BETWEEN TO_DATE(#{startDate}, 'YYYY-MM-DD') AND TO_DATE(#{endDate}, 'YYYY-MM-DD')
ORDER BY REPORT_DATE DESC
